import{_ as s,C as i,o as r,c as n,a5 as a,b as h,w as t,a as c,E as p,a6 as l}from"./chunks/framework.JW9VOlAI.js";const b=JSON.parse('{"title":"Personas Overview","description":"","frontmatter":{},"headers":[],"relativePath":"overview/personas.md","filePath":"overview/personas.md"}'),d={name:"overview/personas.md"};function v(m,e,u,f,w,P){const o=i("Mermaid");return r(),n("div",null,[e[1]||(e[1]=a('<h1 id="personas-overview" tabindex="-1">Personas Overview <a class="header-anchor" href="#personas-overview" aria-label="Permalink to &quot;Personas Overview&quot;">​</a></h1><p>Platform Mesh recognizes three distinct personas that together form the ecosystem. Most platform discussions focus on two roles -- the platform team and the developers who use it. Platform Mesh introduces a third persona, the service provider, that is just as important. Each persona has a dedicated page with detailed workflows and guidance; this page introduces all three and shows how they relate.</p><h2 id="platform-owner" tabindex="-1">Platform Owner <a class="header-anchor" href="#platform-owner" aria-label="Permalink to &quot;Platform Owner&quot;">​</a></h2><p>The platform owner operates the Platform Mesh infrastructure itself -- kcp, identity (Keycloak), authorization (OpenFGA), and the service marketplace. They onboard service providers, manage the <a href="/pr-preview/pr-80/concepts/account-model.html">account hierarchy</a>, and define the organizational policies that govern the ecosystem. Think of them as the operator of the marketplace.</p><p><a href="/pr-preview/pr-80/overview/platform-owner.html">Read more: Platform Owner →</a></p><h2 id="service-provider" tabindex="-1">Service Provider <a class="header-anchor" href="#service-provider" aria-label="Permalink to &quot;Service Provider&quot;">​</a></h2><p>Service providers build and operate services within the ecosystem. They define <strong>what</strong> can be ordered (the API schema) and <strong>how</strong> it gets fulfilled (the controller logic). Any team that runs a service -- databases, certificates, CI/CD pipelines, AI/ML infrastructure, or anything else -- can become a provider by exposing a KRM API for that service. Providers are first-class participants with their own workspaces, API definitions, and lifecycle management.</p><p><a href="/pr-preview/pr-80/overview/providers.html">Read more: Service Providers →</a></p><h2 id="service-consumer" tabindex="-1">Service Consumer <a class="header-anchor" href="#service-consumer" aria-label="Permalink to &quot;Service Consumer&quot;">​</a></h2><p>Developers, data scientists, and application owners who discover services through the marketplace, order capabilities by creating resource documents, and manage their lifecycle through KRM. Consumers interact with every provider through the same tools and patterns -- <code>kubectl</code>, GitOps, IaC, or the <a href="/pr-preview/pr-80/overview/architecture.html#ui-layer">Platform Mesh Portal</a> -- regardless of what the service is, who provides it, or where it runs.</p><p><a href="/pr-preview/pr-80/overview/consumers.html">Read more: Service Consumers →</a></p><h2 id="how-personas-interact" tabindex="-1">How Personas Interact <a class="header-anchor" href="#how-personas-interact" aria-label="Permalink to &quot;How Personas Interact&quot;">​</a></h2>',12)),(r(),h(l,null,{default:t(()=>[p(o,{id:"mermaid-36",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20PO%5B%22Platform%20Owner%22%5D%0A%20%20%20%20SP%5B%22Service%20Provider%22%5D%0A%20%20%20%20SC%5B%22Service%20Consumer%22%5D%0A%20%20%20%20PM%5B%22Platform%20Mesh%3Cbr%3E(kcp%20%2B%20Account%20Model)%22%5D%0A%20%20%20%20MP%5B%22Service%20Marketplace%3Cbr%3E(APIExports)%22%5D%0A%0A%20%20%20%20PO%20--%20%22operates%22%20--%3E%20PM%0A%20%20%20%20PO%20--%20%22onboards%22%20--%3E%20SP%0A%20%20%20%20SP%20--%20%22publishes%20APIs%20to%22%20--%3E%20MP%0A%20%20%20%20SC%20--%20%22discovers%20%26%20binds%20from%22%20--%3E%20MP%0A%20%20%20%20MP%20--%20%22hosted%20in%22%20--%3E%20PM%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<p>The platform owner sets up the infrastructure and onboards providers. Providers publish their service APIs as <a href="/pr-preview/pr-80/concepts/api-export-binding.html">APIExports</a>. Consumers discover these services and bind to them, creating a self-service ecosystem where the control plane mediates all interactions.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-80/overview/platform-owner.html">Platform Owner</a> -- deploying, governing, and operating the mesh</li><li><a href="/pr-preview/pr-80/overview/providers.html">Service Providers</a> -- how providers publish and fulfill services</li><li><a href="/pr-preview/pr-80/overview/consumers.html">Service Consumers</a> -- how consumers discover and use services</li><li><a href="/pr-preview/pr-80/overview/integration-paths.html">Integration Paths</a> -- technical options for bringing services into the mesh</li><li><a href="/pr-preview/pr-80/concepts/account-model.html">Account Model</a> -- how organizational structure maps to workspaces</li></ul>',3))])}const _=s(d,[["render",v]]);export{b as __pageData,_ as default};
